INSERT INTO `policiesI18n` (`PolicyID`, `LanguageID`, `Content`, `SwalTitle`, `HeaderButtonText`, `AcceptButtonText`, `DeclineButtonText`, `CreatedAt`, `UpdatedAt`) VALUES (1, 2, 'En utilisant cet outil de consultation des données, vous reconnaissez qu''il s''agit d''une version bêta et qu''il peut ne pas fonctionner comme prévu. Vous vous engagez également à l''utiliser de manière responsable et à ne pas faire un usage abusif des données.','Conditions d''utilisation','Conditions d''utilisation','Oui, j''accepte','Déclin','2026-05-28 10:54:21','2026-05-28 10:54:21');
INSERT INTO `policiesI18n` (`PolicyID`, `LanguageID`, `Content`, `SwalTitle`, `HeaderButtonText`, `AcceptButtonText`, `DeclineButtonText`, `CreatedAt`, `UpdatedAt`) VALUES (2, 2, 'En utilisant cette instance de LORIS, vous reconnaissez savoir qu''elle contient des données de test et non des données réelles d''utilisateurs.','Conditions d''utilisation','Conditions d''utilisation','J''accepte','','2026-05-28 10:54:21','2026-05-28 10:54:21');
INSERT INTO `policiesI18n` (`PolicyID`, `LanguageID`, `Content`, `SwalTitle`, `HeaderButtonText`, `AcceptButtonText`, `DeclineButtonText`, `CreatedAt`, `UpdatedAt`) VALUES (1, 3, 'このデータクエリツールをご利用になる場合、本ツールがベータ版であり、期待どおりに動作しない可能性があることをご承知おきください。また、責任を持って利用し、データを悪用しないことに同意するものとします。','利用規約','利用規約','はい、承知しました','お断りします','2026-05-28 10:54:21','2026-05-28 10:54:21');
INSERT INTO `policiesI18n` (`PolicyID`, `LanguageID`, `Content`, `SwalTitle`, `HeaderButtonText`, `AcceptButtonText`, `DeclineButtonText`, `CreatedAt`, `UpdatedAt`) VALUES (2, 3, 'このLORISインスタンスをご利用になることで、お客様は、本インスタンスが実際のユーザーデータではなくテストデータで構成されていることを承知しているものとします。','利用規約','利用規約','同意します','','2026-05-28 10:54:21','2026-05-28 10:54:21');
INSERT INTO `policiesI18n` (`PolicyID`, `LanguageID`, `Content`, `SwalTitle`, `HeaderButtonText`, `AcceptButtonText`, `DeclineButtonText`, `CreatedAt`, `UpdatedAt`) VALUES (1, 4, 'इस डेटा क्वेरी टूल का उपयोग करके, आप स्वीकार करते हैं कि यह बीटा में है और हो सकता है कि यह अपेक्षित रूप से काम न करे। आप इसके जिम्मेदारीपूर्वक उपयोग करने और डेटा का दुरुपयोग न करने के लिए भी सहमत हैं।','उपयोग की शर्तें','उपयोग की शर्तें','हाँ, मैं स्वीकार करता हूँ।','मैं अस्वीकार करता हूँ','2026-05-28 10:54:21','2026-05-28 10:54:21');
INSERT INTO `policiesI18n` (`PolicyID`, `LanguageID`, `Content`, `SwalTitle`, `HeaderButtonText`, `AcceptButtonText`, `DeclineButtonText`, `CreatedAt`, `UpdatedAt`) VALUES (2, 4, 'इस LORIS इंस्टेंस का उपयोग करके आप स्वीकार करते हैं कि आप जानते हैं कि यह परीक्षण डेटा से भरा है, न कि वास्तविक उपयोगकर्ता डेटा से।','उपयोग की शर्तें','उपयोग की शर्तें','मैं स्वीकार करता हूँ','','2026-05-28 10:54:21','2026-05-28 10:54:21');
